import { useEffect, useState } from "react";

function Dashboard() {
    const [matches, setMatches] = useState([]);

    useEffect(() => {
        fetch("/api/matches")
            .then(res => res.json())
            .then(data => {
                if (Array.isArray(data)) {
                    setMatches(data);
                } else if (data.content) {
                    setMatches(data.content);
                } else {
                    setMatches([]);
                }
            });
    }, []);

    return (
        <div style={{ display: "flex", gap: "20px", padding: "20px" }}>
            <div style={{ flex: 1 }}>
                <h3>Matches</h3>
                <ul>
                    {matches.map(m => (
                        <li key={m.id}>
                            {m.teamA} vs {m.teamB} —{" "}
                            {m.matchTime ? new Date(m.matchTime).toLocaleString() : "TBD"}
                        </li>
                    ))}
                </ul>
            </div>
        </div>
    );
}

export default Dashboard;
